@@ -0,0 +1,51 @@
+import { prisma } from "db";
+import { TRPCError } from "@trpc/server";
+
+export interface CreateGuestClientInput {
+  firstName: string;
+  lastName?: string | null;
+  email: string;
+  phone?: string | null;
+  note?: string | null;
+}
+
+export interface CreateGuestClientOutput {
+  id: string;
+  firstName: string;
+  lastName: string | null;
+  email: string;
+  phone: string | null;
+  note: string | null;
+}
+
+export class CreateGuestClient {
+  async execute(
+    businessId: string,
+    input: CreateGuestClientInput
+  ): Promise<CreateGuestClientOutput> {
+    // Check if user already exists
+    const existingUser = await prisma.user.findUnique({
+      where: { email: input.email },
+    });
+
+    if (existingUser) {
+      throw new TRPCError({
+        code: "CONFLICT",
+        message: "A user with this email already exists",
+      });
+    }
+
+    // Create guest user
+    const user = await prisma.user.create({
+      data: {
+        firstName: input.firstName,
+        lastName: input.lastName,
+        email: input.email,
+        phone: input.phone,
+        note: input.note,
+        isGuest: true,
+      },
+    });
+
+    return user;
+  }
+}
diff --git a/apps/web-app/src/server/trpc/routers/client.router.ts b/apps/web-app/src/server/trpc/routers/client.router.ts
--- /dev/null
+++ b/apps/web-app/src/server/trpc/routers/client.router.ts
@@ -0,0 +1,73 @@
+import { z } from "zod";
+import { createTRPCRouter, protectedProcedure } from "../trpc";
+import { PrismaClientRepository } from "@/server/infrastructure/repositories/PrismaClientRepository";
+import { CreateGuestClient } from "@/server/core/application/use-cases/client/CreateGuestClient";
+
+const clientRepository = new PrismaClientRepository();
+const createGuestClient = new CreateGuestClient();
+
+export const clientRouter = createTRPCRouter({
+  getByBusiness: protectedProcedure
+    .input(
+      z.object({
+        search: z.string().optional(),
+        limit: z.number().min(1).max(100).default(20),
+        offset: z.number().min(0).default(0),
+      })
+    )
+    .query(async ({ ctx, input }) => {
+      const businessId = ctx.session.user.activeBusinessId;
+      if (!businessId) {
+        throw new Error("No active business");
+      }
+
+      const [clients, total] = await Promise.all([
+        clientRepository.findByBusiness(businessId, input),
+        clientRepository.countByBusiness(businessId, input),
+      ]);
+
+      return { clients, total };
+    }),
+
+  getStats: protectedProcedure.query(async ({ ctx }) => {
+    const businessId = ctx.session.user.activeBusinessId;
+    if (!businessId) {
+      throw new Error("No active business");
+    }
+
+    return clientRepository.getStats(businessId);
+  }),
+
+  getDetail: protectedProcedure
+    .input(
+      z.object({
+        customerId: z.string(),
+      })
+    )
+    .query(async ({ ctx, input }) => {
+      const businessId = ctx.session.user.activeBusinessId;
+      if (!businessId) {
+        throw new Error("No active business");
+      }
+
+      return clientRepository.getDetail(businessId, input.customerId);
+    }),
+
+  createGuest: protectedProcedure
+    .input(
+      z.object({
+        firstName: z.string().min(1),
+        lastName: z.string().nullable().optional(),
+        email: z.string().email(),
+        phone: z.string().nullable().optional(),
+        note: z.string().nullable().optional(),
+      })
+    )
+    .mutation(async ({ ctx, input }) => {
+      const businessId = ctx.session.user.activeBusinessId;
+      if (!businessId) {
+        throw new Error("No active business");
+      }
+
+      return createGuestClient.execute(businessId, input);
+    }),
+});
