+ * Business logic for updating user profile information.
+ * Handles validation and orchestrates the update process.
+ *
+ * @module core/application/use-cases/user
+ */
+
+import type { IUserRepository } from "@/core/domain/repositories/IUserRepository";
+import type { UpdateProfilePersonalInfoInput } from "@/lib/validations/user.schema";
+
+/**
+ * Input data for updating a user
+ */
+export interface UpdateUserInput {
+  id: string;
+  data: UpdateProfilePersonalInfoInput;
+}
+
+/**
+ * Result of update user operation
+ */
+export type UpdateUserResult =
+  | { success: true }
+  | { success: false; error: string };
+
+/**
+ * Use case for updating user profile information
+ *
+ * @example
+ * ```typescript
+ * const updateUserUseCase = new UpdateUserUseCase(userRepository);
+ * 
+ * const result = await updateUserUseCase.execute({
+ *   id: "user-123",
+ *   data: {
+ *     firstName: "John",
+ *     lastName: "Doe",
+ *     phone: "987654321"
+ *   }
+ * });
+ * ```
+ */
+export class UpdateUserUseCase {
+  constructor(private readonly userRepository: IUserRepository) {}
+
+  async execute(input: UpdateUserInput): Promise<UpdateUserResult> {
+    try {
+      const { id, data } = input;
+
+      // Update user in repository
+      const success = await this.userRepository.update(id, {
+        firstName: data.firstName,
+        lastName: data.lastName,
+        birthday: data.birthday || null,
+        phone: data.phone || null,
+        countryCode: data.countryCode || null,
+        timeZone: data.timeZone || null,
+      });
+
+      return success ? { success: true } : { success: false, error: "Update failed" };
+    } catch (error) {
+      return { success: false, error: error instanceof Error ? error.message : "Unknown error" };
+    }
+  }
+}
